function DataAnalystAgent() {
  const [csv, setCsv] = React.useState('');
  const [insights, setInsights] = React.useState(null);
  const [chartData, setChartData] = React.useState([]);
  const [busy, setBusy] = React.useState(false);
  const onFile = (e) => {
    const f = e.target.files?.[0]; if (!f) return;
    const reader = new FileReader();
    reader.onload = () => setCsv(String(reader.result || ''));
    reader.readAsText(f);
  };
  const analyze = async () => {
    if (!csv.trim()) return;
    setBusy(true); setInsights(null);
    try {
      const r = await titan.api.call('/api/message', { method: 'POST', body: { content: `Profile this CSV and return JSON: { "rows": <int>, "columns": [<names>], "insights": [<5 bullets>], "chart": { "label": <col>, "value": <col> }, "chartData": [{ "label": "...", "value": <num> }, ... up to 12] }\n\nCSV:\n${csv.slice(0, 8000)}` } });
      const text = r?.content || r?.text || '';
      const m = text.match(/\{[\s\S]*\}/);
      if (m) {
        const p = JSON.parse(m[0]);
        setInsights(p);
        setChartData(p.chartData || []);
      }
    } catch (e) { setInsights({ error: String(e?.message||e) }); }
    setBusy(false);
  };
  const max = Math.max(...chartData.map(d=>Number(d.value)||0), 1);
  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',gap:8}}>
      <div style={{fontSize:16,fontWeight:600}}>📊 Data Analyst</div>
      <div style={{display:'flex',gap:6}}>
        <input type="file" accept=".csv" onChange={onFile} style={{flex:1,fontSize:12}}/>
        <button onClick={analyze} disabled={busy||!csv} style={{padding:'6px 14px',border:'none',borderRadius:6,background:'#007AFF',color:'#fff',cursor:busy?'wait':'pointer',fontWeight:600}}>{busy?'…':'Analyze'}</button>
      </div>
      <textarea value={csv} onChange={e=>setCsv(e.target.value)} placeholder="Paste CSV or upload a file" rows={3} style={{padding:8,border:'1px solid #ccc',borderRadius:6,fontSize:11,fontFamily:'ui-monospace,monospace',resize:'vertical'}}/>
      <div style={{flex:1,overflow:'auto'}}>
        {insights && !insights.error && (
          <>
            <div style={{display:'flex',gap:8,marginBottom:8}}>
              <div style={{padding:'6px 10px',background:'#E3F2FD',borderRadius:6,fontSize:12}}><b>{insights.rows}</b> rows</div>
              <div style={{padding:'6px 10px',background:'#F3E5F5',borderRadius:6,fontSize:12}}><b>{insights.columns?.length||0}</b> cols</div>
            </div>
            {insights.insights?.map((it,i) => <div key={i} style={{padding:'6px 10px',marginBottom:4,background:'#FFF7E6',borderLeft:'3px solid #FF9500',borderRadius:4,fontSize:12}}>{it}</div>)}
            {chartData.length > 0 && (
              <div style={{marginTop:10,padding:8,background:'#fff',border:'1px solid #eee',borderRadius:8}}>
                {chartData.map((d,i) => (
                  <div key={i} style={{display:'grid',gridTemplateColumns:'80px 1fr 60px',alignItems:'center',gap:6,padding:'2px 0',fontSize:11}}>
                    <div style={{overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{d.label}</div>
                    <div style={{height:14,background:'#eee',borderRadius:4}}><div style={{width:`${(Number(d.value)/max)*100}%`,height:'100%',background:'#007AFF',borderRadius:4}}/></div>
                    <div style={{textAlign:'right',fontVariantNumeric:'tabular-nums'}}>{Number(d.value).toLocaleString()}</div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}
        {insights?.error && <div style={{color:'#FF3B30'}}>{insights.error}</div>}
      </div>
    </div>
  );
}
render(<DataAnalystAgent/>);
